import type { Metadata } from 'next'
import { notFound } from 'next/navigation'
import { BackButton } from '@/components/NavigationButtons'

type Post = { id: number; title: string; body: string }
type Comment = { id: number; name: string; body: string; email: string }
type Params = { id: string }

export async function generateStaticParams(): Promise<Params[]> {
  const response = await fetch('https://jsonplaceholder.typicode.com/posts')
  if (!response.ok) return []
  const posts = (await response.json()) as Post[]
  return posts.slice(0, 10).map(post => ({ id: String(post.id) }))
}

async function getPost(id: string): Promise<{ post: Post; comments: Comment[] } | null> {
  const [postResponse, commentsResponse] = await Promise.all([fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, { next: { revalidate: 300 } }), fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, { next: { revalidate: 300 } })])
  if (!postResponse.ok || !commentsResponse.ok) return null
  return { post: (await postResponse.json()) as Post, comments: (await commentsResponse.json()) as Comment[] }
}

export async function generateMetadata({ params }: { params: Promise<Params> }): Promise<Metadata> {
  const { id } = await params
  const data = await getPost(id)
  if (!data) return { title: 'Post Not Found - My Blog' }
  const description = data.post.body.substring(0, 160)
  return { title: `${data.post.title} - My Blog`, description, openGraph: { title: data.post.title, description } }
}

export default async function BlogPost({ params }: { params: Promise<Params> }) {
  const { id } = await params
  const data = await getPost(id)
  if (!data) notFound()
  const { post, comments } = data
  return <><article><BackButton /><h1>{post.title}</h1><p>{post.body}</p><h2>Comments ({comments.length})</h2><div className="comments">{comments.map(comment => <div key={comment.id} className="comment"><h3>{comment.name}</h3><p>{comment.body}</p><small>By: {comment.email}</small></div>)}</div></article></>
}
