import { NextResponse } from 'next/server'

type Params = { id: string }
type UpdatePost = { title?: string; content?: string }

export async function GET(_request: Request, { params }: { params: Promise<Params> }) {
  const { id } = await params
  return NextResponse.json({ id: Number.parseInt(id, 10), title: `Post ${id}`, content: `This is the content for post ${id}`, createdAt: new Date().toISOString() })
}

export async function PUT(request: Request, { params }: { params: Promise<Params> }) {
  const { id } = await params
  const { title, content } = (await request.json()) as UpdatePost
  return NextResponse.json({ id: Number.parseInt(id, 10), title: title || `Post ${id}`, content: content || `Updated content for post ${id}`, updatedAt: new Date().toISOString() })
}

export async function DELETE(_request: Request, { params }: { params: Promise<Params> }) {
  const { id } = await params
  return NextResponse.json({ message: `Post ${id} deleted successfully` })
}
EOF
